(function(){
  'use strict';
  const ham = document.querySelector('.hamburger');
  const navUl = document.querySelector('nav ul');
  if(ham && navUl){
    ham.addEventListener('click',function(){
      navUl.classList.toggle('open');
      ham.setAttribute('aria-expanded', navUl.classList.contains('open'));
    });
    document.addEventListener('click',function(e){
      if(!ham.contains(e.target) && !navUl.contains(e.target)){
        navUl.classList.remove('open');
      }
    });
  }
  const links = document.querySelectorAll('nav ul li a');
  const path = window.location.pathname.split('/').pop() || 'index.html';
  links.forEach(function(a){
    if(a.getAttribute('href') === path) a.classList.add('active');
  });
  const scrollBtn = document.getElementById('scrolltop');
  if(scrollBtn){
    window.addEventListener('scroll',function(){
      scrollBtn.classList.toggle('visible', window.scrollY > 400);
    });
    scrollBtn.addEventListener('click',function(){
      window.scrollTo({top:0,behavior:'smooth'});
    });
  }
  const observer = new IntersectionObserver(function(entries){
    entries.forEach(function(entry){
      if(entry.isIntersecting){
        entry.target.style.animationPlayState='running';
        const fills = entry.target.querySelectorAll('.skill-bar-fill');
        fills.forEach(function(f){
          f.style.width = f.dataset.width;
        });
        observer.unobserve(entry.target);
      }
    });
  },{threshold:0.12});
  document.querySelectorAll('.fade-up, .card, .ref-card, .step, .team-card').forEach(function(el){
    el.style.animationPlayState='paused';
    el.classList.add('fade-up');
    observer.observe(el);
  });
  document.querySelectorAll('section').forEach(function(s){
    observer.observe(s);
  });
  const cookieBanner = document.getElementById('cookie-banner');
  const cookieAccept = document.getElementById('cookie-accept');
  if(cookieBanner && cookieAccept){
    if(localStorage.getItem('dg_cookies')) cookieBanner.classList.add('hidden');
    cookieAccept.addEventListener('click',function(){
      localStorage.setItem('dg_cookies','1');
      cookieBanner.classList.add('hidden');
    });
  }
  document.querySelectorAll('.faq-q').forEach(function(btn){
    btn.addEventListener('click',function(){
      const answer = this.nextElementSibling;
      const isOpen = this.classList.contains('open');
      document.querySelectorAll('.faq-q.open').forEach(function(b){
        b.classList.remove('open');
        b.nextElementSibling.style.maxHeight='0';
      });
      if(!isOpen){
        this.classList.add('open');
        answer.style.maxHeight = answer.scrollHeight+'px';
      }
    });
  });
  function animateCounter(el, target, duration){
    const start = Date.now();
    const isFloat = target%1 !== 0;
    function update(){
      const p = Math.min((Date.now()-start)/duration, 1);
      const ease = 1 - Math.pow(1-p, 3);
      const val = isFloat ? (target*ease).toFixed(1) : Math.floor(target*ease);
      el.textContent = val + el.dataset.suffix;
      if(p < 1) requestAnimationFrame(update);
    }
    requestAnimationFrame(update);
  }
  const statsObs = new IntersectionObserver(function(entries){
    entries.forEach(function(entry){
      if(entry.isIntersecting){
        const el = entry.target;
        animateCounter(el, parseFloat(el.dataset.count), 1800);
        statsObs.unobserve(el);
      }
    });
  },{threshold:0.5});
  document.querySelectorAll('[data-count]').forEach(function(el){
    el.textContent = '0' + (el.dataset.suffix||'');
    statsObs.observe(el);
  });
  document.querySelectorAll('a[href^="#"]').forEach(function(a){
    a.addEventListener('click',function(e){
      const target = document.querySelector(this.getAttribute('href'));
      if(target){
        e.preventDefault();
        target.scrollIntoView({behavior:'smooth', block:'start'});
      }
    });
  });
  window.showNotification = function(msg){
    let n = document.querySelector('.notification');
    if(!n){ n=document.createElement('div'); n.className='notification'; document.body.appendChild(n); }
    n.textContent = msg;
    n.classList.add('show');
    setTimeout(function(){ n.classList.remove('show'); }, 3500);
  };
  if(!('loading' in HTMLImageElement.prototype)){
    const imgs = document.querySelectorAll('img[loading="lazy"]');
    const imgObs = new IntersectionObserver(function(entries){
      entries.forEach(function(e){
        if(e.isIntersecting){
          e.target.src = e.target.dataset.src || e.target.src;
          imgObs.unobserve(e.target);
        }
      });
    });
    imgs.forEach(function(img){ imgObs.observe(img); });
  }
})();
